<template><el-card><template #header>知识切片管理</template><PageToolbar><el-input v-model="q" placeholder="搜索切片内容"/><template #actions><el-button>批量向量化</el-button></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="content" label="切片内容" min-width="260"/><el-table-column prop="asset" label="来源资产"/><el-table-column prop="page" label="页码"/><el-table-column prop="clause" label="条款号"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="region" label="区域"/><el-table-column prop="vectorStatus" label="向量状态"/><el-table-column prop="hits" label="命中次数"/><el-table-column label="健康度"><template #default="s"><HealthScore :level="s.row.health"/></template></el-table-column><el-table-column label="操作" width="220"><template #default="s"><el-button link type="primary" @click="detail=s.row">详情</el-button><el-button link @click="s.row.vectorStatus='已向量化'">重新向量化</el-button><el-button link type="danger" @click="s.row.enabled=false">禁用</el-button><el-button link>调整元数据</el-button></template></el-table-column></DataTable><DetailDrawer v-model="open" title="切片详情"><pre>{{detail}}</pre></DetailDrawer></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { chunks } from '@/mock/data'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; import HealthScore from '@/components/HealthScore.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(chunks))); const q=ref(''); const filtered=computed(()=>rows.value.filter(i=>!q.value||i.content.includes(q.value))); const detail=ref<any>(); const open=computed({get:()=>!!detail.value,set:v=>{if(!v)detail.value=null}});</script>
